//! KYC case verbs (5 plugin verbs) — YAML-first re-implementation of
//! `kyc-case.*` + `entity-workstream.state` from
//! `rust/config/verbs/kyc-case.yaml`.
//!
//! Ops:
//! - `kyc-case.create` — deal-aware intake: validates deal status in
//!   KYC_ELIGIBLE_DEAL_STATUSES, infers client_group_id from deal when
//!   not supplied. `case_ref` auto-generated by DB trigger.
//! - `kyc-case.update-status` — FSM-gated transition via
//!   [`LifecycleCatalog`] service; rejects terminal statuses (callers
//!   must use `close`).
//! - `kyc-case.close` — enforces REVIEW → terminal, emits
//!   `KYC_GATE_COMPLETED` deal event when APPROVED with linked deal.
//! - `kyc-case.summarize` — full case view: workstreams with embedded
//!   `awaiting` requests + attention items (overdue, priority).
//! - `entity-workstream.state` — single workstream view: awaiting
//!   requests + completed screenings + received documents.
//!
//! Legacy `sqlx::query!` macros swapped for runtime `sqlx::query_as` /
//! `sqlx::query_scalar` (offline-cache–free, slice #10 pattern).

use anyhow::{anyhow, Result};
use async_trait::async_trait;
use chrono::{DateTime, NaiveDate, Utc};
use serde::{Deserialize, Serialize};
use serde_json::{json, Value};
use sqlx::types::BigDecimal;
use uuid::Uuid;

use dsl_runtime::domain_ops::helpers::{
    json_extract_string, json_extract_string_opt, json_extract_uuid, json_extract_uuid_opt,
};
use dsl_runtime::service_traits::LifecycleCatalog;
use dsl_runtime::tx::TransactionScope;
use dsl_runtime::{VerbExecutionContext, VerbExecutionOutcome};

use super::SemOsVerbOp;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct KycCaseCreateResult {
    pub case_id: Uuid,
    pub case_ref: String,
    pub cbu_id: Uuid,
    pub deal_id: Option<Uuid>,
    pub client_group_id: Option<Uuid>,
    pub case_type: String,
    pub status: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct KycCaseCloseResult {
    pub case_id: Uuid,
    pub status: String,
    pub closed_at: String,
    pub deal_gate_updated: bool,
}

const KYC_ELIGIBLE_DEAL_STATUSES: &[&str] = &[
    "NEGOTIATING",
    "KYC_CLEARANCE",
    "CONTRACTED",
    "ONBOARDING",
    "ACTIVE",
];

const CLOSE_STATUSES: &[&str] = &[
    "APPROVED",
    "REJECTED",
    "WITHDRAWN",
    "EXPIRED",
    "REFER_TO_REGULATOR",
    "DO_NOT_ONBOARD",
];

fn is_valid_transition(catalog: &dyn LifecycleCatalog, from: &str, to: &str) -> bool {
    catalog.is_valid_transition("kyc_case", from, to)
}

fn is_terminal_status(catalog: &dyn LifecycleCatalog, status: &str) -> bool {
    CLOSE_STATUSES.contains(&status) && catalog.is_terminal_state("kyc_case", status)
}

fn valid_next_statuses(catalog: &dyn LifecycleCatalog, status: &str) -> String {
    catalog.valid_next_states("kyc_case", status).join(", ")
}

// ---------------------------------------------------------------------------
// kyc-case.create
// ---------------------------------------------------------------------------

pub struct Create;

#[async_trait]
impl SemOsVerbOp for Create {
    fn fqn(&self) -> &str {
        "kyc-case.create"
    }
    async fn execute(
        &self,
        args: &Value,
        ctx: &mut VerbExecutionContext,
        scope: &mut dyn TransactionScope,
    ) -> Result<VerbExecutionOutcome> {
        let cbu_id = json_extract_uuid(args, ctx, "cbu-id")?;
        let deal_id = json_extract_uuid_opt(args, ctx, "deal-id");
        let mut client_group_id = json_extract_uuid_opt(args, ctx, "client-group-id");
        let case_type = json_extract_string_opt(args, "case-type")
            .unwrap_or_else(|| "NEW_CLIENT".to_string());
        let sla_deadline: Option<String> = json_extract_string_opt(args, "sla-deadline");
        let assigned_analyst_id = json_extract_uuid_opt(args, ctx, "assigned-analyst-id");
        let notes = json_extract_string_opt(args, "notes");

        if let Some(did) = deal_id {
            let row: Option<(String, Uuid)> = sqlx::query_as(
                r#"SELECT deal_status, primary_client_group_id
                   FROM "ob-poc".deals
                   WHERE deal_id = $1"#,
            )
            .bind(did)
            .fetch_optional(scope.executor())
            .await?;

            let (deal_status, deal_client_group_id) =
                row.ok_or_else(|| anyhow!("Deal not found: {}", did))?;

            if !KYC_ELIGIBLE_DEAL_STATUSES.contains(&deal_status.as_str()) {
                return Err(anyhow!(
                    "Deal {} is in status '{}', but KYC case creation requires one of: {}",
                    did,
                    deal_status,
                    KYC_ELIGIBLE_DEAL_STATUSES.join(", ")
                ));
            }

            if client_group_id.is_none() {
                client_group_id = Some(deal_client_group_id);
            }
        }

        let case_id = Uuid::new_v4();
        let case_ref: String = sqlx::query_scalar(
            r#"INSERT INTO "ob-poc".cases (
                   case_id, cbu_id, case_type, sla_deadline,
                   assigned_analyst_id, notes, deal_id, client_group_id
               )
               VALUES ($1, $2, $3, $4::timestamptz, $5, $6, $7, $8)
               RETURNING case_ref"#,
        )
        .bind(case_id)
        .bind(cbu_id)
        .bind(&case_type)
        .bind(&sla_deadline)
        .bind(assigned_analyst_id)
        .bind(&notes)
        .bind(deal_id)
        .bind(client_group_id)
        .fetch_one(scope.executor())
        .await?;

        // Phase C.3 rollout (F7 follow-on, 2026-04-22): emit
        // PendingStateAdvance for the new KYC case. Always emits —
        // kyc-case.create is not idempotent (every call creates a
        // fresh case_id), so every successful execution is a genuine
        // state transition.
        dsl_runtime::domain_ops::helpers::emit_pending_state_advance(
            ctx,
            case_id,
            "kyc-case:intake",
            "kyc-case/workstream",
            "kyc-case.create — new KYC case at intake",
        );

        let result = KycCaseCreateResult {
            case_id,
            case_ref,
            cbu_id,
            deal_id,
            client_group_id,
            case_type,
            status: "INTAKE".to_string(),
        };
        Ok(VerbExecutionOutcome::Record(serde_json::to_value(result)?))
    }
}

// ---------------------------------------------------------------------------
// kyc-case.update-status
// ---------------------------------------------------------------------------

pub struct UpdateStatus;

#[async_trait]
impl SemOsVerbOp for UpdateStatus {
    fn fqn(&self) -> &str {
        "kyc-case.update-status"
    }
    async fn execute(
        &self,
        args: &Value,
        ctx: &mut VerbExecutionContext,
        scope: &mut dyn TransactionScope,
    ) -> Result<VerbExecutionOutcome> {
        let catalog = ctx.service::<dyn LifecycleCatalog>()?;
        let case_id = json_extract_uuid(args, ctx, "case-id")?;
        let requested_status = json_extract_string(args, "status")?;
        let notes = json_extract_string_opt(args, "notes");

        if is_terminal_status(catalog.as_ref(), &requested_status) {
            return Err(anyhow!(
                "Use kyc-case.close for terminal status '{}'. The update-status verb handles non-terminal transitions only.",
                requested_status
            ));
        }

        let current_status: String =
            sqlx::query_scalar(r#"SELECT status FROM "ob-poc".cases WHERE case_id = $1"#)
                .bind(case_id)
                .fetch_optional(scope.executor())
                .await?
                .ok_or_else(|| anyhow!("KYC case not found: {}", case_id))?;

        if !is_valid_transition(catalog.as_ref(), &current_status, &requested_status) {
            return Err(anyhow!(
                "Invalid transition: {} → {}. Allowed transitions from {}: [{}]",
                current_status,
                requested_status,
                current_status,
                valid_next_statuses(catalog.as_ref(), &current_status)
            ));
        }

        sqlx::query(
            r#"UPDATE "ob-poc".cases
               SET status = $2,
                   notes = COALESCE($3, notes),
                   updated_at = NOW()
               WHERE case_id = $1"#,
        )
        .bind(case_id)
        .bind(&requested_status)
        .bind(&notes)
        .execute(scope.executor())
        .await?;

        // Phase C.3 rollout: state-transition emission. Status lives in
        // the DAG as `kyc-case:<lowercase-status>`. The LifecycleCatalog
        // service validates `is_valid_transition` above, so reaching
        // this line guarantees a genuine advance occurred.
        let to_node = format!("kyc-case:{}", requested_status.to_lowercase());
        let reason = format!(
            "kyc-case.update-status — {} → {}",
            current_status, requested_status
        );
        dsl_runtime::domain_ops::helpers::emit_pending_state_advance(
            ctx,
            case_id,
            &to_node,
            "kyc-case/workstream",
            &reason,
        );

        Ok(VerbExecutionOutcome::Affected(1))
    }
}

// ---------------------------------------------------------------------------
// kyc-case.close
// ---------------------------------------------------------------------------

pub struct Close;

#[async_trait]
impl SemOsVerbOp for Close {
    fn fqn(&self) -> &str {
        "kyc-case.close"
    }
    async fn execute(
        &self,
        args: &Value,
        ctx: &mut VerbExecutionContext,
        scope: &mut dyn TransactionScope,
    ) -> Result<VerbExecutionOutcome> {
        let case_id = json_extract_uuid(args, ctx, "case-id")?;
        let status = json_extract_string(args, "status")?;
        let notes = json_extract_string_opt(args, "notes");

        if !CLOSE_STATUSES.contains(&status.as_str()) {
            return Err(anyhow!(
                "Invalid close status '{}'. Must be one of: {}",
                status,
                CLOSE_STATUSES.join(", ")
            ));
        }

        let row: Option<(String, Option<Uuid>, Option<String>)> = sqlx::query_as(
            r#"SELECT status, deal_id, case_ref
               FROM "ob-poc".cases
               WHERE case_id = $1"#,
        )
        .bind(case_id)
        .fetch_optional(scope.executor())
        .await?;
        let (current_status, deal_id, case_ref) =
            row.ok_or_else(|| anyhow!("KYC case not found: {}", case_id))?;

        if current_status != "REVIEW" {
            return Err(anyhow!(
                "KYC case {} is in status '{}', but must be in REVIEW to close",
                case_id,
                current_status
            ));
        }

        let closed_at: String = sqlx::query_scalar(
            r#"UPDATE "ob-poc".cases
               SET status = $2,
                   closed_at = NOW(),
                   notes = COALESCE($3, notes),
                   updated_at = NOW()
               WHERE case_id = $1
               RETURNING to_char(closed_at, 'YYYY-MM-DD"T"HH24:MI:SS"Z"')"#,
        )
        .bind(case_id)
        .bind(&status)
        .bind(&notes)
        .fetch_one(scope.executor())
        .await?;

        let mut deal_gate_updated = false;
        if status == "APPROVED" {
            if let Some(did) = deal_id {
                let event_id = Uuid::new_v4();
                let detail = json!({
                    "case_id": case_id,
                    "case_ref": case_ref,
                    "approved_at": closed_at,
                    "gate": "KYC"
                });
                sqlx::query(
                    r#"INSERT INTO "ob-poc".deal_events
                           (event_id, deal_id, event_type, subject_type, subject_id, new_value, description)
                       VALUES ($1, $2, 'KYC_GATE_COMPLETED', 'KYC_CASE', $3, 'APPROVED', $4)"#,
                )
                .bind(event_id)
                .bind(did)
                .bind(case_id)
                .bind(detail.to_string())
                .execute(scope.executor())
                .await?;
                deal_gate_updated = true;
            }
        }

        // Phase C.3 rollout: terminal state transition. A close is
        // always a genuine state advance (we validated REVIEW → closed
        // above). Terminal status determines the DAG target node.
        let to_node = format!("kyc-case:{}", status.to_lowercase());
        let reason = format!(
            "kyc-case.close — REVIEW → {} (deal_gate_updated={})",
            status, deal_gate_updated
        );
        dsl_runtime::domain_ops::helpers::emit_pending_state_advance(
            ctx,
            case_id,
            &to_node,
            "kyc-case/workstream",
            &reason,
        );

        let result = KycCaseCloseResult {
            case_id,
            status,
            closed_at,
            deal_gate_updated,
        };
        Ok(VerbExecutionOutcome::Record(serde_json::to_value(result)?))
    }
}

// ---------------------------------------------------------------------------
// kyc-case.summarize
// ---------------------------------------------------------------------------

pub struct Summarize;

#[async_trait]
impl SemOsVerbOp for Summarize {
    fn fqn(&self) -> &str {
        "kyc-case.summarize"
    }
    async fn execute(
        &self,
        args: &Value,
        ctx: &mut VerbExecutionContext,
        scope: &mut dyn TransactionScope,
    ) -> Result<VerbExecutionOutcome> {
        let case_id = json_extract_uuid(args, ctx, "case-id")?;

        #[derive(sqlx::FromRow)]
        struct CaseRow {
            case_id: Uuid,
            status: String,
            risk_rating: Option<String>,
            case_type: Option<String>,
            escalation_level: Option<i32>,
            opened_at: Option<DateTime<Utc>>,
            sla_deadline: Option<DateTime<Utc>>,
            cbu_id: Uuid,
            cbu_name: String,
            client_type: Option<String>,
        }
        let case_row: CaseRow = sqlx::query_as(
            r#"
            SELECT
                c.case_id,
                c.status,
                c.risk_rating,
                c.case_type,
                c.escalation_level,
                c.opened_at,
                c.sla_deadline,
                cb.cbu_id,
                cb.name as cbu_name,
                cb.client_type
            FROM "ob-poc".cases c
            JOIN "ob-poc".cbus cb ON c.cbu_id = cb.cbu_id
            WHERE c.case_id = $1
              AND cb.deleted_at IS NULL
            "#,
        )
        .bind(case_id)
        .fetch_optional(scope.executor())
        .await?
        .ok_or_else(|| anyhow!("Case not found: {}", case_id))?;

        #[derive(sqlx::FromRow)]
        struct WsRow {
            workstream_id: Uuid,
            entity_id: Uuid,
            status: String,
            is_ubo: Option<bool>,
            ownership_percentage: Option<BigDecimal>,
            ws_risk_rating: Option<String>,
            requires_enhanced_dd: Option<bool>,
            blocker_type: Option<String>,
            blocker_message: Option<String>,
            entity_name: String,
        }
        let workstreams: Vec<WsRow> = sqlx::query_as(
            r#"
            SELECT
                w.workstream_id,
                w.entity_id,
                w.status,
                w.is_ubo,
                w.ownership_percentage,
                w.risk_rating as ws_risk_rating,
                w.requires_enhanced_dd,
                w.blocker_type,
                w.blocker_message,
                e.name as entity_name
            FROM "ob-poc".entity_workstreams w
            JOIN "ob-poc".entities e ON w.entity_id = e.entity_id
            WHERE w.case_id = $1
              AND e.deleted_at IS NULL
            ORDER BY w.created_at
            "#,
        )
        .bind(case_id)
        .fetch_all(scope.executor())
        .await?;

        let mut workstream_states: Vec<Value> = Vec::new();
        let mut total_awaiting = 0usize;
        let mut overdue_count = 0usize;

        for ws in &workstreams {
            let role: Option<String> = sqlx::query_scalar(
                r#"
                SELECT r.name
                FROM "ob-poc".cbu_entity_roles cer
                JOIN "ob-poc".roles r ON cer.role_id = r.role_id
                WHERE cer.entity_id = $1 AND cer.cbu_id = $2
                LIMIT 1
                "#,
            )
            .bind(ws.entity_id)
            .bind(case_row.cbu_id)
            .fetch_optional(scope.executor())
            .await?;

            #[derive(sqlx::FromRow)]
            struct AwaitingRow {
                request_id: Uuid,
                request_type: Option<String>,
                request_subtype: Option<String>,
                requested_from_label: Option<String>,
                requested_at: Option<DateTime<Utc>>,
                due_date: Option<NaiveDate>,
                reminder_count: Option<i32>,
                escalation_level: Option<i32>,
                #[allow(dead_code)]
                status: Option<String>,
                #[allow(dead_code)]
                blocker_message: Option<String>,
                days_overdue: Option<i32>,
            }
            let awaiting_rows: Vec<AwaitingRow> = sqlx::query_as(
                r#"
                SELECT
                    request_id,
                    request_type,
                    request_subtype,
                    requested_from_label,
                    requested_at,
                    due_date,
                    reminder_count,
                    escalation_level,
                    status,
                    blocker_message,
                    (CURRENT_DATE - due_date)::int4 as days_overdue
                FROM "ob-poc".outstanding_requests
                WHERE workstream_id = $1 AND status IN ('PENDING', 'ESCALATED')
                ORDER BY due_date ASC
                "#,
            )
            .bind(ws.workstream_id)
            .fetch_all(scope.executor())
            .await?;

            let awaiting_nodes: Vec<Value> = awaiting_rows
                .iter()
                .map(|r| {
                    let days_over = r.days_overdue.unwrap_or(0).max(0);
                    let is_overdue = days_over > 0;
                    if is_overdue {
                        overdue_count += 1;
                    }
                    let mut actions = vec!["remind", "extend"];
                    if is_overdue {
                        actions.push("escalate");
                    }
                    actions.push("waive");
                    json!({
                        "request_id": r.request_id,
                        "type": r.request_type,
                        "subtype": r.request_subtype,
                        "from": r.requested_from_label,
                        "requested_at": r.requested_at,
                        "due_date": r.due_date,
                        "days_overdue": days_over,
                        "overdue": is_overdue,
                        "reminder_count": r.reminder_count,
                        "escalated": r.escalation_level.unwrap_or(0) > 0,
                        "actions": actions
                    })
                })
                .collect();

            total_awaiting += awaiting_nodes.len();
            workstream_states.push(json!({
                "workstream_id": ws.workstream_id,
                "entity": {
                    "entity_id": ws.entity_id,
                    "name": ws.entity_name,
                    "role": role
                },
                "status": ws.status,
                "is_ubo": ws.is_ubo,
                "ownership_percentage": ws.ownership_percentage.as_ref().map(|d| d.to_string()),
                "risk_rating": ws.ws_risk_rating,
                "requires_enhanced_dd": ws.requires_enhanced_dd,
                "blocker_type": ws.blocker_type,
                "blocker_message": ws.blocker_message,
                "awaiting": awaiting_nodes
            }));
        }

        let complete_count = workstream_states
            .iter()
            .filter(|w| w["status"] == "COMPLETE")
            .count();
        let blocked_count = workstream_states
            .iter()
            .filter(|w| w["status"] == "BLOCKED")
            .count();
        let in_progress_count = workstream_states
            .iter()
            .filter(|w| {
                let s = w["status"].as_str().unwrap_or("");
                s != "COMPLETE" && s != "BLOCKED" && s != "PENDING"
            })
            .count();

        let empty_vec = vec![];
        let attention: Vec<Value> = workstream_states
            .iter()
            .flat_map(|ws| {
                let awaiting = ws["awaiting"].as_array().unwrap_or(&empty_vec);
                awaiting
                    .iter()
                    .filter(|r| r["overdue"].as_bool().unwrap_or(false))
                    .map(|r| {
                        let days = r["days_overdue"].as_i64().unwrap_or(0);
                        let priority = if days > 7 { "HIGH" } else { "MEDIUM" };
                        json!({
                            "workstream": ws["workstream_id"],
                            "entity": ws["entity"]["name"],
                            "issue": format!("{} overdue {} days",
                                r["subtype"].as_str().unwrap_or("Request"),
                                days),
                            "priority": priority,
                            "actions": r["actions"]
                        })
                    })
                    .collect::<Vec<_>>()
            })
            .collect();

        Ok(VerbExecutionOutcome::Record(json!({
            "case_id": case_row.case_id,
            "cbu": {
                "cbu_id": case_row.cbu_id,
                "name": case_row.cbu_name,
                "client_type": case_row.client_type
            },
            "status": case_row.status,
            "risk_rating": case_row.risk_rating,
            "case_type": case_row.case_type,
            "escalation_level": case_row.escalation_level,
            "opened_at": case_row.opened_at,
            "sla_deadline": case_row.sla_deadline,
            "workstreams": workstream_states,
            "summary": {
                "total_workstreams": workstream_states.len(),
                "complete": complete_count,
                "in_progress": in_progress_count,
                "blocked": blocked_count,
                "total_awaiting": total_awaiting,
                "overdue": overdue_count
            },
            "attention": attention
        })))
    }
}

// ---------------------------------------------------------------------------
// entity-workstream.state
// ---------------------------------------------------------------------------

pub struct WorkstreamState;

#[async_trait]
impl SemOsVerbOp for WorkstreamState {
    fn fqn(&self) -> &str {
        "entity-workstream.state"
    }
    async fn execute(
        &self,
        args: &Value,
        ctx: &mut VerbExecutionContext,
        scope: &mut dyn TransactionScope,
    ) -> Result<VerbExecutionOutcome> {
        let workstream_id = json_extract_uuid(args, ctx, "workstream-id")?;

        #[derive(sqlx::FromRow)]
        struct WsRow {
            workstream_id: Uuid,
            case_id: Uuid,
            entity_id: Uuid,
            status: String,
            is_ubo: Option<bool>,
            ownership_percentage: Option<BigDecimal>,
            risk_rating: Option<String>,
            requires_enhanced_dd: Option<bool>,
            blocker_type: Option<String>,
            blocker_message: Option<String>,
            entity_name: String,
            cbu_id: Uuid,
        }
        let ws: WsRow = sqlx::query_as(
            r#"
            SELECT
                w.workstream_id,
                w.case_id,
                w.entity_id,
                w.status,
                w.is_ubo,
                w.ownership_percentage,
                w.risk_rating,
                w.requires_enhanced_dd,
                w.blocker_type,
                w.blocker_message,
                e.name as entity_name,
                c.cbu_id
            FROM "ob-poc".entity_workstreams w
            JOIN "ob-poc".entities e ON w.entity_id = e.entity_id
            JOIN "ob-poc".cases c ON w.case_id = c.case_id
            WHERE w.workstream_id = $1
              AND e.deleted_at IS NULL
            "#,
        )
        .bind(workstream_id)
        .fetch_optional(scope.executor())
        .await?
        .ok_or_else(|| anyhow!("Workstream not found: {}", workstream_id))?;

        let role: Option<String> = sqlx::query_scalar(
            r#"
            SELECT r.name
            FROM "ob-poc".cbu_entity_roles cer
            JOIN "ob-poc".roles r ON cer.role_id = r.role_id
            WHERE cer.entity_id = $1 AND cer.cbu_id = $2
            LIMIT 1
            "#,
        )
        .bind(ws.entity_id)
        .bind(ws.cbu_id)
        .fetch_optional(scope.executor())
        .await?;

        #[derive(sqlx::FromRow)]
        struct AwaitingRow {
            request_id: Uuid,
            request_type: Option<String>,
            request_subtype: Option<String>,
            requested_from_label: Option<String>,
            requested_at: Option<DateTime<Utc>>,
            due_date: Option<NaiveDate>,
            reminder_count: Option<i32>,
            escalation_level: Option<i32>,
            #[allow(dead_code)]
            status: Option<String>,
            days_overdue: Option<i32>,
        }
        let awaiting_rows: Vec<AwaitingRow> = sqlx::query_as(
            r#"
            SELECT
                request_id,
                request_type,
                request_subtype,
                requested_from_label,
                requested_at,
                due_date,
                reminder_count,
                escalation_level,
                status,
                (CURRENT_DATE - due_date)::int4 as days_overdue
            FROM "ob-poc".outstanding_requests
            WHERE workstream_id = $1 AND status IN ('PENDING', 'ESCALATED')
            ORDER BY due_date ASC
            "#,
        )
        .bind(workstream_id)
        .fetch_all(scope.executor())
        .await?;

        let awaiting: Vec<Value> = awaiting_rows
            .iter()
            .map(|r| {
                let days_over = r.days_overdue.unwrap_or(0).max(0);
                let is_overdue = days_over > 0;
                let mut actions = vec!["remind", "extend"];
                if is_overdue {
                    actions.push("escalate");
                }
                actions.push("waive");
                json!({
                    "request_id": r.request_id,
                    "type": r.request_type,
                    "subtype": r.request_subtype,
                    "from": r.requested_from_label,
                    "requested_at": r.requested_at,
                    "due_date": r.due_date,
                    "days_overdue": days_over,
                    "overdue": is_overdue,
                    "reminder_count": r.reminder_count,
                    "escalated": r.escalation_level.unwrap_or(0) > 0,
                    "actions": actions
                })
            })
            .collect();

        #[derive(sqlx::FromRow)]
        struct ScreeningRow {
            screening_type: String,
            status: String,
            completed_at: Option<DateTime<Utc>>,
        }
        let screenings: Vec<ScreeningRow> = sqlx::query_as(
            r#"
            SELECT screening_type, status, completed_at
            FROM "ob-poc".screenings
            WHERE workstream_id = $1 AND status NOT IN ('PENDING', 'RUNNING')
            ORDER BY completed_at DESC
            "#,
        )
        .bind(workstream_id)
        .fetch_all(scope.executor())
        .await?;

        let checks_complete: Vec<Value> = screenings
            .iter()
            .map(|s| json!({
                "type": s.screening_type,
                "result": s.status,
                "date": s.completed_at
            }))
            .collect();

        #[derive(sqlx::FromRow)]
        struct DocRow {
            document_type_code: Option<String>,
            doc_id: Uuid,
            created_at: Option<DateTime<Utc>>,
        }
        let documents: Vec<DocRow> = sqlx::query_as(
            r#"
            SELECT d.document_type_code, d.doc_id, d.created_at
            FROM "ob-poc".document_catalog d
            JOIN "ob-poc".outstanding_requests r ON d.doc_id = r.fulfillment_reference_id
            WHERE r.workstream_id = $1 AND r.status = 'FULFILLED'
            ORDER BY d.created_at DESC
            "#,
        )
        .bind(workstream_id)
        .fetch_all(scope.executor())
        .await?;

        let documents_received: Vec<Value> = documents
            .iter()
            .map(|d| json!({
                "type": d.document_type_code,
                "document_id": d.doc_id,
                "date": d.created_at
            }))
            .collect();

        Ok(VerbExecutionOutcome::Record(json!({
            "workstream_id": ws.workstream_id,
            "case_id": ws.case_id,
            "entity": {
                "entity_id": ws.entity_id,
                "name": ws.entity_name,
                "role": role
            },
            "status": ws.status,
            "is_ubo": ws.is_ubo,
            "ownership_percentage": ws.ownership_percentage.as_ref().map(|d| d.to_string()),
            "risk_rating": ws.risk_rating,
            "requires_enhanced_dd": ws.requires_enhanced_dd,
            "blocker_type": ws.blocker_type,
            "blocker_message": ws.blocker_message,
            "awaiting": awaiting,
            "checks_complete": checks_complete,
            "documents_received": documents_received
        })))
    }
}
